def en_uzun_k_ulke(ulke_kodlari, k):
    if k <= 0:
        return 0
    sayim = {}
    sol = 0
    en_uzun = 0
    for sag in range(len(ulke_kodlari)):
        sayim[ulke_kodlari[sag]] = sayim.get(ulke_kodlari[sag], 0) + 1
        while len(sayim) > k:
            sayim[ulke_kodlari[sol]] -= 1
            if sayim[ulke_kodlari[sol]] == 0:
                del sayim[ulke_kodlari[sol]]
            sol += 1
        en_uzun = max(en_uzun, sag - sol + 1)
    return en_uzun
